insert into public.posts (slug, title_vi, title_en, excerpt_vi, excerpt_en, content_vi, content_en, cover_image, category, status, published_at)
values
  ('he-thong-scada-nha-may-thuy-dien-song-chay-5', 'DTCA cung cấp, thi công hệ thống SCADA Nhà máy thủy điện Sông Chảy 5', 'DTCA delivers the SCADA system for Song Chay 5 Hydropower Plant', 'Năm 2024, DTCA đã triển khai cung cấp và thi công trọn gói hệ thống SCADA cho Nhà máy thủy điện Sông Chảy 5 tại huyện Xín Mần, tỉnh Hà Giang, đảm bảo tiến độ và tiêu chí an toàn - chất lượng.', 'In 2024, DTCA delivered and installed a turnkey SCADA system for Song Chay 5 Hydropower Plant in Xin Man District, Ha Giang Province, meeting all safety and quality requirements on schedule.', 'Nhà máy thủy điện Sông Chảy 5 là một trong những dự án tiêu biểu mà DTCA đã đồng hành cùng Công ty CP Thủy điện Sông Chảy 5 trong năm 2024.
